#include <bits/stdc++.h>
using namespace std;

int n;
long long f[65];

int main() {
    cin >> n;
    f[0] = f[1] = 1;
    for (int i = 2; i <= n; i++) {
        if (i >= 3) {
            f[i] = f[i - 1] + f[i - 2] + f[i - 3];
        }
        else {
            f[i] = f[i - 1] + f[i - 2];
        }
    }
    cout << f[n];
    return 0;
}
